head.script:
/**
 * нҷ” л©ҙ лӘ… : кі„м •мқҙл ҘмЎ°нҡҢ
 * л©”лүҙкІҪлЎң : нҡҢкі„/мһ¬л¬ҙнҡҢкі„/кё°мӨҖм •ліҙ/кі„м •мқҙл ҘмЎ°нҡҢ
 * ASISкІҪлЎң : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/stdinfomgnt/fi_100_01_01p.jsp
 * мһ‘ м„ұ мһҗ : л°°кё°мӣҗ
 * мһ‘ м—… мқј : 2025-10-02
 * мһ‘м—…лӮҙмҡ© :
 *    1. нҷ”л©ҙм„ёнҢ…
 *    2. мҙҲкё°м„ёнҢ…(UDC), к·ёлҰ¬л“ң(лҚ°мқҙн„°лҰ¬мҠӨнҠё)
 *    3. мҠӨнҒ¬лҰҪнҠё TOBEм „нҷҳ
 *    4. кё°лҠҘнҷ•мқё(лІ„нҠј) : м—‘м…ҖлӢӨмҡҙлЎңл“ң мһ‘м—…(мІ«лқјмқём—җ м ңлӘ©лӮҳмҳӨлҸ„лЎқ мІҳлҰ¬)
 *    5. [мҷ„лЈҢ]GauceUtil.getGridCombo("XXXXX",false) кіөнҶөмҪ”л“ң к°Җм ёмҳӨлҠ”кұ° мһ‘м—…мІҳлҰ¬н•ҙм•ј н•Ё.
 *    6. [мҷ„лЈҢ, 2025-10-23]к·ёлҰ¬л“ң readOnly = true мӢң к·ёлҰ¬л“ңм…Җ мғү м•ҲлЁ№нһҳ
 * м°ёкі мӮ¬н•ӯ :
 *    1. к·ёлҰ¬л“ң fixedColumn мӢң л§Ҳм§Җл§ү columnмқҳ лӢӨмқҢ columnмқҙ мӣҖм§Ғмқҙм§Җ м•ҠлҠ” нҳ„мғҒ мҲҳм •н•ҙм•јн•Ё.
 *       мҳҲ)fixedColumn = "5" мқё кІҪмҡ° 5мһҗлҰ¬к№Ңм§Җ мқҙлҸҷ л¶Ҳк°Җн•ҙм•јн•ҳлҠ”лҚ° 6мһҗлҰ¬л¶Җн„° мқҙлҸҷл¶Ҳк°ҖлҗЁ(мқёмҠӨмӣЁмқҙлёҢм—җм„ң кіөнҶөмІҳлҰ¬ мҳҲм •)
 * мҲҳм •мқҙл Ҙ :
 *    - 2025-10-02      л°°кё°мӣҗ    мөңмҙҲмһ‘м„ұ
 */
/**
  * TOBE : мҙҲкё°лЎңл“ң(UDC мһҲмңјл©ҙ scwin.onUdcCompleted мҙҲкё°к°’ м„ёнҢ…)
 */
scwin.onpageload = function() {

};

/**
 * мҙҲкё°м„ёнҢ…(TOBE к·ёлҰ¬л“ң, мҙқкұҙмҲҳ)
 */
scwin.setInit = function() {
    ds_mst.removeAll();
    totalRows.setValue("0");
};

/**
 * UDCк°’ мҙҲкё°нҷ”(scwin.onpageload мқҙнӣ„ м„ёнҢ…лҗЁ)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
    scwin.f_SetDataHeader();
};

/**
 *  DataSetмқҳ Header м •ліҙ мғқм„ұ
 */
scwin.f_SetDataHeader = function() {
    // мЎ°нҡҢмЎ°кұҙмҡ© DataSet Header мҙҲкё°нҷ”
    // var GAUCE_DATASET_HEADER = "crn:STRING";
    // ds_condition.SetDataHeader(GAUCE_DATASET_HEADER);
    // ds_condition.AddRow();

    const codeOptions = [
        { grpCd: "FI001", compID: "gr_mst:acctClsCd" }  //кі„м •кө¬л¶„
      , { grpCd: "FI002", compID: "gr_mst:drcrClsCd" }  //м°ЁлҢҖкө¬л¶„
      , { grpCd: "FI035", compID: "gr_mst:acctLvl"   }  //кі„м •л ҲлІЁ
      , { grpCd: "CO014", compID: "gr_mst:aggrClsCd" }  //м§‘кі„кө¬л¶„
      , { grpCd: "FI027", compID: "gr_mst:mgntNoCd" }   //кҙҖлҰ¬лІҲнҳё
      , { grpCd: "FI094", compID: "gr_mst:pchsTaxAmtDeductYn" }  //л§Өмһ…м„ём•Ўл¶Ҳкіөм ң
    ];
    $c.data.setCommonCode(codeOptions, scwin.callBackCommonCode);

};

/**
 * $c.data.setCommonCode н•ЁмҲҳмқҳ мҪңл°ұн•ЁмҲҳ
 */
scwin.callBackCommonCode = function() {
    dlt_commonCodeFI027.insertJSON(0, [{
        "grpCd": "FI027",
        "cd": "0",
        "cdNm": "0"
    }]);
    dlt_commonCodeFI027.reform();

    scwin.params = $c.data.getParameter();
    if (!$c.util.isEmpty(scwin.params["acctCd"])) {
        dma_search.set("acctCd", scwin.params["acctCd"]);
    }
    scwin.f_Retrieve();
};

/**
 * мЎ°нҡҢ
 */
scwin.f_Retrieve = function() {
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    let rowCnt = ds_mst.getRowCount();
    totalRows.setValue(rowCnt)
    if (rowCnt > 0) {
        gr_mst.setFocusedCell(0, 0);
    }
    let columInfo = $c.gus.f_GetColumnNames(ds_mst);
    //к·ёлҰ¬л“ң м»¬лҹјмғү ліҖкІҪ
    for (let j=0; j < columInfo.length; j++) {
        for (let i=0; i < rowCnt; i++) {
            //к·ёлҰ¬л“ңмІҙнҒ¬л°•мҠӨ к°’ мҲҳм •(м—‘м…Җм—җм„ң мІҙнҒ¬л°•мҠӨ 0, 1к°’мқ„ F, TлЎң ліҖкІҪн•ҳкё° мң„н•Ё)
            if(columInfo[j] == "slipProcYn"
            || columInfo[j] == "termMgntYn"
            || columInfo[j] == "clntMgntYn"
            || columInfo[j] == "empMgntYn"
            || columInfo[j] == "dtMgntYn"
            || columInfo[j] == "substSlipCntlYn"
            || columInfo[j] == "corCardDeductYn"
            || columInfo[j] == "advcdCntlYn"
            || columInfo[j] == "transferSlipYn"
            || columInfo[j] == "expenseSlipYn"
            || columInfo[j] == "privateCorCardYn") {
                let checkValue = ds_mst.getOriginalCellData(i, columInfo[j]);
                ds_mst.setCellData(i, columInfo[j], scwin.decodeYnExp(checkValue));
            }

            /**
             * к·ёлҰ¬л“ң мғү м§Җм • лЎңм§Ғ(мІ«лІҲм§ё rowлҠ” л№„көҗ м•Ҳн•Ё)
             * asis : <script language="javascript"  for=gr_mst event=OnUserColor(Row,eventid)>
             */
            if(i > 0) {
                let iPre = i-1;
                if (ds_mst.getOriginalCellData(iPre, columInfo[j]) != ds_mst.getOriginalCellData(i, columInfo[j])) {
                    if (columInfo[j] == "modId" || columInfo[j] == "histDate") {
                        continue;
                    } else if (columInfo[j] == "slipProcYn"
                        || columInfo[j] == "termMgntYn"
                        || columInfo[j] == "clntMgntYn"
                        || columInfo[j] == "empMgntYn"
                        || columInfo[j] == "dtMgntYn"
                        || columInfo[j] == "substSlipCntlYn"
                        || columInfo[j] == "corCardDeductYn"
                        || columInfo[j] == "advcdCntlYn"
                        || columInfo[j] == "transferSlipYn"
                        || columInfo[j] == "expenseSlipYn"
                        || columInfo[j] == "privateCorCardYn"
                    ) {
                        gr_mst.setCellBackgroundColor(i, columInfo[j], "#C1F3FF");
                    } else {
                        gr_mst.setCellColor(i, columInfo[j], "blue");
                    }
                }
            }
        }
        ds_mst.reform();
        //л§Ҳм§Җл§үrowм—җ мҲҳм •мһҗ, мҲҳм •мқјмһҗ м»¬лҹјмғү ліҖкІҪ
        if (columInfo[j] == "modId" || columInfo[j] == "histDate") {
            gr_mst.setCellBackgroundColor(rowCnt - 1, columInfo[j], "#FFD8D8");
        }
    }
};

scwin.decodeYnExp = function (data) {
    return $c.gus.decode(data, "0", "F", "1", "T", "F");
};

//-------------------------------------------------------------------------
// м—‘м…Җ нҢҢмқј лӢӨмҡҙлЎңл“ң
//-------------------------------------------------------------------------
scwin.f_RunExcel = async function () {
    let totCnt = ds_mst.getRowCount();
    let sheetTitle = "кі„м •мқҙл ҘлӘ©лЎқ";
    if (!(totCnt > 0)) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // мЎ°нҡҢкІ°кіјк°Җ мЎҙмһ¬н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ
        return;
    }
    //asis м—‘м…Җмҳөм…ҳ      
    // gridName.SetExcelTitle(1, "value:" + sheetName + ";"     // н‘ңмӢңн•  нғҖмқҙнӢҖ
    //                               + "font-face:'лҸӢмӣҖмІҙ';"	// нҸ°нҠё
    //                               + "font-size:12pt;"		// нҸ°нҠё нҒ¬кё°
    //                               + "font-color:black;"	// нҸ°нҠё мғүк№”
    //                               + "bgcolor:#ffffff;"	      // л°°кІҪ мғүк№”
    //                               + "align:center;"		// м •л ¬
    //                               + "line-color:white;"	// нғҖмқҙнӢҖ л¶Җл¶„ н…Ңл‘җлҰ¬м„  мғүк№”
    //                               + "line-width:0pt;"		// нғҖмқҙнӢҖ н…Ңл‘җлҰ¬м„  көөкё°
    //                               + "skiprow:1;")		// нғҖмқҙнӢҖ лӢӨмқҢ л–јлҠ” лЎңмҡ° мҲҳ
    //                               ;
    // cfGridToExcel(gridName, sheetName, fileName, 4 + 8 + 16);

    let cfrm = await $c.win.confirm("EXCELлЎң лӢӨмҡҙлЎңл“ң л°ӣмңјмӢңкІ мҠөлӢҲк№Ң?");
    if (cfrm) {
        let options = {
            fileName: sheetTitle,    // + ".xls",
            sheetName: sheetTitle,
            type: "1",
            headerColor: "#eeeeee", //"#E8E8E8", //м—°н•ңнҡҢмғү #33CCCC
            startRowIndex: 2
        };
        //к·ёлҰ¬л“ңм—җ лҢҖн•ң лӮҙмҡ©мқ„ м¶”к°Җ мҳөм…ҳ
        let infoArr = [
            //м ңлӘ©
            {
                rowIndex: 0               //м ңлӘ©мқ„ н‘ңмӢңн•  н–ү index
                , colIndex: 0               //м ңлӘ©мқ„ н‘ңмӢңн•  м—ҙ index
                , rowSpan: 1                //лі‘н•©н•  н–үмқҳ мҲҳ
                , colSpan: 25               //лі‘н•©н•  м—ҙмқҳ мҲҳ
                , text: sheetTitle          //н‘ңмӢңн•  лӮҙмҡ©(м ңлӘ©)
                , textAlign: "center"       //н‘ңмӢңн•  лӮҙмҡ©мқҳ м •л ¬ л°©лІ•(left, center, right)
                , fontSize: "12px"          //нҸ°нҠё size
                , fontName: "лҸӢмӣҖмІҙ"        //нҸ°нҠёмқҙлҰ„ 
                , drawBorder: false         //cellмқҳ border м§Җм •(true, false)
            }
        ];

        $c.data.downloadGridViewExcel(gr_mst, options, infoArr);
    }
};

/**
 * лӢ«кё°
 */
scwin.f_WinClose = function (e) {
    let rt = ["N/A"];
    $c.win.closePopup(rt);
};
